#[cfg(test)]
mod tests {
    use sha2::{Digest, Sha256};

    // pins tools/gen-shaders/src/main.rs as of the last regeneration
    const GEN_SRC_HASH: &str = "361fc0112f5a2563db7c5946cd7563558c6fb8b1afc6255e7047f46e85705b34";
    const FILL_HASH: &str = "fc5835983ccf4d335c426d2e2335fe980ce26cfcf2146743269b84badd871b1a";
    const TEX_HASH: &str = "887e2cd45d7dd2ed6d02cf485122a0b78ead554b984208d780d387c33eadcd0c";
    const TEXR_HASH: &str = "8bec46dc9fab3ef52d985194a19ea7bd17f4781c6efaad5a429f818deb85bbaf";
    const BORDER_HASH: &str = "bf7c0a7986d2920d6caad0c68a5c42d6a34a63e3fa7e99eda6e3be024ace70e6";
    const SHADOW_HASH: &str = "cafaedbc4b3d306c4ce84d65d14321fafbab334c5e2af8aba002a4ca8a3d9750";
    const XFADE_HASH: &str = "8cd299aca8b8ec6541b18e477fc158d564aa8a6cf76e81144e5eed59d736f669";
    const BLUR_DOWN_HASH: &str = "34204c10289c2596de466ddc4b884a87c8cf834185df10591262d0608aa5cab1";
    const BLUR_UP_HASH: &str = "449fe9666f33e893cafbc255e9397dd622af62f9856f1ebc04e418474cd4f185";
    const BLUR_MASK_HASH: &str = "4e65fac3843b1b33c306f9728f6b9b0c2a22b1f61c28993f84a00bac1429c035";
    const REGEN: &str =
        "shaders out of date - rerun: cargo run --manifest-path tools/gen-shaders/Cargo.toml";

    fn hex(b: &[u8]) -> String {
        b.iter().map(|x| format!("{x:02x}")).collect()
    }

    fn words_hash(words: &[u32]) -> String {
        let mut h = Sha256::new();
        for w in words {
            h.update(w.to_le_bytes());
        }
        hex(&h.finalize())
    }

    #[test]
    fn generator_matches_committed_words() {
        let gen_src = include_str!("../../tools/gen-shaders/src/main.rs");
        assert_eq!(GEN_SRC_HASH, hex(&Sha256::digest(gen_src.as_bytes())), "{REGEN}");
        assert_eq!(FILL_HASH, words_hash(super::FILL), "{REGEN}");
        assert_eq!(TEX_HASH, words_hash(super::TEX), "{REGEN}");
        assert_eq!(TEXR_HASH, words_hash(super::TEXR), "{REGEN}");
        assert_eq!(BORDER_HASH, words_hash(super::BORDER), "{REGEN}");
        assert_eq!(SHADOW_HASH, words_hash(super::SHADOW), "{REGEN}");
        assert_eq!(XFADE_HASH, words_hash(super::XFADE), "{REGEN}");
        assert_eq!(BLUR_DOWN_HASH, words_hash(super::BLUR_DOWN), "{REGEN}");
        assert_eq!(BLUR_UP_HASH, words_hash(super::BLUR_UP), "{REGEN}");
        assert_eq!(BLUR_MASK_HASH, words_hash(super::BLUR_MASK), "{REGEN}");
    }

    #[test]
    fn shader_words_are_spirv() {
        assert_eq!(super::FILL[0], 0x0723_0203);
        assert_eq!(super::TEX[0], 0x0723_0203);
        assert_eq!(super::TEXR[0], 0x0723_0203);
        assert_eq!(super::BORDER[0], 0x0723_0203);
        assert_eq!(super::SHADOW[0], 0x0723_0203);
        assert_eq!(super::XFADE[0], 0x0723_0203);
        assert_eq!(super::BLUR_DOWN[0], 0x0723_0203);
        assert_eq!(super::BLUR_UP[0], 0x0723_0203);
        assert_eq!(super::BLUR_MASK[0], 0x0723_0203);
    }
}
